const d = $input.first().json.body;

const esc = (v) => String(v ?? '').replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#39;');
const br = (v) => esc(v).replace(/\n/g, '<br/>');
const euro = (v) => new Intl.NumberFormat('nl-NL', { style: 'currency', currency: 'EUR' }).format(v);
const dateFmt = (v) => new Intl.DateTimeFormat('nl-NL', { dateStyle: 'long' }).format(new Date(v));

const factuurNr = esc(d.invoiceNumber ?? 'ONBEKEND');
const subtotal = Number(d.subtotal ?? 0);
const vatRate = Number(d.vatRate ?? 21);
const vatAmount = Number(d.vatAmount ?? subtotal * vatRate / 100);
const totalAmount = Number(d.totalAmount ?? subtotal + vatAmount);
const serviceDate = d.serviceDate ? dateFmt(d.serviceDate) : dateFmt(d.issueDate);

const fromName = esc(d.from?.companyName ?? '');
const fromEmail = esc(d.from?.email ?? '');
const fromWebsite = esc(d.from?.websiteUrl ?? '');
const fromAddress = br(d.from?.address ?? '');
const fromVat = esc(d.from?.vatNumber ?? '');
const fromKvk = esc(d.from?.kvkNumber ?? '');
const fromIban = esc(d.from?.iban ?? '');
const fromBank = esc(d.from?.bankName ?? '');

const html = `<!DOCTYPE html>
<html lang="nl">
<head>
<meta charset="UTF-8"/>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: 'Helvetica Neue', Arial, sans-serif; font-size: 13px; line-height: 1.6; color: #1a1a1a; background: #fff; padding: 52px 56px; }
  .page-header { display: flex; justify-content: space-between; align-items: flex-start; padding-bottom: 28px; border-bottom: 3px solid #111; margin-bottom: 36px; }
  .company-name { font-size: 24px; font-weight: 800; color: #111; letter-spacing: -.5px; }
  .company-sub { font-size: 11px; color: #666; margin-top: 3px; }
  .doc-title { text-align: right; }
  .doc-title h1 { font-size: 28px; font-weight: 800; color: #111; letter-spacing: -1px; }
  .doc-title .meta { font-size: 11px; color: #555; line-height: 1.9; margin-top: 4px; }
  .doc-title .meta strong { color: #111; }
  .parties { display: grid; grid-template-columns: 1fr 1fr; gap: 24px; margin-bottom: 36px; }
  .party { background: #f8f9fa; border-radius: 8px; padding: 18px 20px; }
  .party-label { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .1em; color: #999; margin-bottom: 8px; }
  .party-name { font-size: 14px; font-weight: 700; color: #111; margin-bottom: 2px; }
  .party-detail { font-size: 12px; color: #444; line-height: 1.7; }
  .section { margin-bottom: 28px; }
  .section-title { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: .08em; color: #666; border-bottom: 1px solid #e5e7eb; padding-bottom: 6px; margin-bottom: 12px; }
  .section p { font-size: 13px; color: #333; line-height: 1.75; }
  .price-table { width: 100%; border-collapse: collapse; margin-bottom: 28px; }
  .price-table th { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .08em; color: #999; padding: 8px 12px; border-bottom: 2px solid #e5e7eb; text-align: left; }
  .price-table th:last-child { text-align: right; }
  .price-table td { padding: 10px 12px; font-size: 13px; border-bottom: 1px solid #f0f0f0; }
  .price-table td:last-child { text-align: right; font-variant-numeric: tabular-nums; }
  .price-table .subtotal-row td { padding-top: 14px; color: #555; }
  .price-table .vat-row td { color: #888; font-size: 12px; }
  .price-table .total-row td { font-size: 16px; font-weight: 700; color: #111; border-top: 2px solid #111; border-bottom: none; padding-top: 12px; }
  .betaal-box { background: #f0fdf4; border: 1px solid #bbf7d0; border-radius: 8px; padding: 18px 20px; margin-bottom: 28px; }
  .betaal-box .label { font-size: 10px; font-weight: 700; text-transform: uppercase; letter-spacing: .08em; color: #16a34a; margin-bottom: 8px; }
  .betaal-box .detail { font-size: 13px; color: #111; line-height: 1.8; }
  .betaal-box .detail strong { font-weight: 700; }
  .page-footer { margin-top: 40px; padding-top: 14px; border-top: 1px solid #e5e7eb; font-size: 10px; color: #aaa; line-height: 1.8; text-align: center; }
</style>
</head>
<body>

<div class="page-header">
  <div>
    <div class="company-name">${fromName}</div>
    <div class="company-sub">${fromWebsite}${fromWebsite && fromEmail ? ' &nbsp;·&nbsp; ' : ''}${fromEmail}</div>
  </div>
  <div class="doc-title">
    <h1>FACTUUR</h1>
    <div class="meta">
      <strong>Factuurnummer:</strong> ${factuurNr}<br/>
      <strong>Factuurdatum:</strong> ${dateFmt(d.issueDate)}<br/>
      <strong>Leverdatum:</strong> ${serviceDate}<br/>
      <strong>Vervaldatum:</strong> ${dateFmt(d.dueDate)}
    </div>
  </div>
</div>

<div class="parties">
  <div class="party">
    <div class="party-label">Van</div>
    <div class="party-name">${fromName}</div>
    <div class="party-detail">
      ${fromAddress ? fromAddress + '<br/>' : ''}
      ${fromEmail}<br/>
      ${fromWebsite ? fromWebsite + '<br/>' : ''}
      ${fromVat ? 'BTW: ' + fromVat + '<br/>' : ''}
      ${fromKvk ? 'KvK: ' + fromKvk : ''}
    </div>
  </div>
  <div class="party">
    <div class="party-label">Aan</div>
    <div class="party-name">${esc(d.client?.companyName ?? '')}</div>
    <div class="party-detail">
      ${esc(d.client?.contactName ?? '')}<br/>
      ${br(d.client?.address ?? '')}<br/>
      ${esc(d.client?.email ?? '')}
    </div>
  </div>
</div>

${d.project ? `
<div class="section">
  <div class="section-title">Project</div>
  <p>${esc(d.project.name)}</p>
</div>` : ''}

<div class="section">
  <div class="section-title">Omschrijving werkzaamheden</div>
  <p>${br(d.description ?? '')}</p>
</div>

<table class="price-table">
  <thead>
    <tr>
      <th>Post</th>
      <th>Bedrag</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>Subtotaal excl. BTW</td>
      <td>${euro(subtotal)}</td>
    </tr>
    <tr class="vat-row">
      <td>BTW ${vatRate}%</td>
      <td>${euro(vatAmount)}</td>
    </tr>
    <tr class="total-row">
      <td>Totaal incl. BTW</td>
      <td>${euro(totalAmount)}</td>
    </tr>
  </tbody>
</table>

<div class="betaal-box">
  <div class="label">Betalingsinformatie</div>
  <div class="detail">
    ${fromIban ? '<strong>IBAN:</strong> ' + fromIban + (fromBank ? ' (' + fromBank + ')' : '') + '<br/>' : ''}
    <strong>Bedrag:</strong> ${euro(totalAmount)}<br/>
    <strong>Vervaldatum:</strong> ${dateFmt(d.dueDate)}<br/>
    <strong>Onder vermelding van:</strong> Factuur ${factuurNr}<br/>
    Gelieve het bovenstaande bedrag uiterlijk op de vervaldatum te voldoen.
    ${fromEmail ? 'Bij vragen kunt u contact opnemen via <strong>' + fromEmail + '</strong>.' : ''}
  </div>
</div>

${d.notes ? `
<div class="section">
  <div class="section-title">Notities</div>
  <p>${br(d.notes)}</p>
</div>` : ''}

<div class="page-footer">
  ${fromName}${fromEmail ? ' &nbsp;·&nbsp; ' + fromEmail : ''}${fromWebsite ? ' &nbsp;·&nbsp; ' + fromWebsite : ''}<br/>
  ${fromVat ? 'BTW: ' + fromVat + ' &nbsp;·&nbsp; ' : ''}${fromKvk ? 'KvK: ' + fromKvk + ' &nbsp;·&nbsp; ' : ''}Factuurnummer ${factuurNr}
</div>

</body>
</html>`;

return [{ json: { ...d, html } }];

const html = $input.first().json.html;
const buffer = Buffer.from(html, 'utf8');
const item = $input.first();
item.binary = { data: { data: buffer.toString('base64'), mimeType: 'application/octet-stream', fileName: 'factuur.html' } };
return [item];
